<?php
 namespace WPAICG\STT; use WP_Error; if (!defined('ABSPATH')) { exit; } abstract class AIPKit_STT_Base_Provider_Strategy implements AIPKit_STT_Provider_Strategy_Interface { protected function decode_json(string $json_string, string $context): array|WP_Error { if (trim($json_string) === '') return []; $decoded = json_decode($json_string, true); if (json_last_error() !== JSON_ERROR_NONE) { $error_message = sprintf(__('Failed to parse JSON response from %1$s. Error: %2$s', 'gpt3-ai-content-generator'), $context, json_last_error_msg()); return new WP_Error('json_decode_error', $error_message); } return is_array($decoded) ? $decoded : []; } protected function parse_error_response($response_body, int $status_code, string $context): string { $message = sprintf(__('An unknown error occurred with %s.', 'gpt3-ai-content-generator'), $context); $decoded = is_string($response_body) ? json_decode($response_body, true) : $response_body; if (is_array($decoded)) { if (!empty($decoded['error']['message'])) $message = $decoded['error']['message']; elseif (!empty($decoded['detail'])) $message = is_string($decoded['detail']) ? $decoded['detail'] : json_encode($decoded['detail']); elseif (!empty($decoded['message'])) $message = $decoded['message']; } elseif (is_string($response_body)) { $message = substr($response_body, 0, 200); } return trim($message); } public function get_request_options(string $operation): array { return [ 'method' => 'POST', 'timeout' => 60, 'user-agent' => 'AIPKit/' . (defined('WPAICG_VERSION') ? WPAICG_VERSION : '1.0') . '; ' . get_bloginfo('url'), 'sslverify' => apply_filters('https_local_ssl_verify', true), ]; } public function get_api_headers(string $api_key, string $operation): array { return [ ]; } abstract public function transcribe_audio(string $audio_data, string $audio_format, array $api_params, array $options = []): string|WP_Error; abstract public function get_supported_formats(): array; }